args.sparql:
SELECT DISTINCT ?state ?stateLabel ?bidenShare ?trumpShare
WHERE {
  wd:Q104664159 wdt:P3222 ?result.
  ?result wdt:P131 ?state.
  ?result wdt:P631 wd:Q6279; wdt:P1107 ?bidenShare.
  ?result wdt:P631 wd:Q3724827; wdt:P1107 ?trumpShare.
  FILTER(?bidenShare - ?trumpShare > 0.1)
  ?state wdt:P31 wd:Q347410.
  SERVICE wikibase:label { bd:serviceParam wikibase:language "[en]". }
}

SELECT ?state ?stateLabel ?bidenShare ?trumpShare
WHERE {
  ?state wdt:P31 wd:Q2612;
         wdt:P17 wd:Q30.
  ?state wdt:P110 ?result.
  ?result wdt:P631 wd:Q6279; wdt:P1107 ?bidenShare.
  ?result wdt:P631 wd:Q3724827; wdt:P1107 ?trumpShare.
  FILTER(?bidenShare > ?trumpShare && ?bidenShare - ?trumpShare > 0.1)
  SERVICE wikibase:label { bd:serviceParam wikibase:language "[en]". }
}
